function BpmCalculator() {
  const [taps, setTaps] = React.useState([]);
  const [bpm, setBpm] = React.useState(0);
  const timeoutRef = React.useRef(null);
  const tap = () => {
    const now = Date.now();
    setTaps((prev) => {
      const next = [...prev, now].slice(-8);
      if (next.length > 1) {
        const intervals = [];
        for (let i = 1; i < next.length; i++) intervals.push(next[i] - next[i - 1]);
        const avg = intervals.reduce((a, b) => a + b, 0) / intervals.length;
        setBpm(Math.round(60000 / avg));
      }
      return next;
    });
    if (timeoutRef.current) clearTimeout(timeoutRef.current);
    timeoutRef.current = setTimeout(() => { setTaps([]); setBpm(0); }, 2000);
  };
  const reset = () => { setTaps([]); setBpm(0); if (timeoutRef.current) clearTimeout(timeoutRef.current); };
  React.useEffect(() => {
    const handler = (e) => { if (e.code === 'Space') { e.preventDefault(); tap(); } };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, []);
  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#fff', borderRadius: 12, height: '100%', boxSizing: 'border-box', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', textAlign: 'center' }}>
      <h3 style={{ margin: '0 0 8px 0', fontSize: 16, color: '#222' }}>Tap Tempo</h3>
      <div style={{ fontSize: 56, fontWeight: 800, color: '#4f46e5', marginBottom: 4, fontVariantNumeric: 'tabular-nums' }}>{bpm || '—'}</div>
      <div style={{ fontSize: 14, color: '#888', marginBottom: 16 }}>BPM</div>
      <button onClick={tap} style={{ width: 140, height: 140, borderRadius: '50%', border: '4px solid #4f46e5', background: 'linear-gradient(135deg, #eef2ff, #e0e7ff)', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 18, fontWeight: 600, color: '#4f46e5', marginBottom: 12, userSelect: 'none' }}>
        TAP
      </button>
      <div style={{ display: 'flex', gap: 6, marginBottom: 12 }}>
        {Array.from({ length: 8 }).map((_, i) => (
          <div key={i} style={{ width: 8, height: 8, borderRadius: '50%', background: i < taps.length ? '#4f46e5' : '#e5e7eb' }} />
        ))}
      </div>
      <button onClick={reset} style={{ padding: '6px 14px', borderRadius: 8, border: '1px solid #ddd', background: '#fff', cursor: 'pointer', fontFamily: 'inherit', fontSize: 12, color: '#666' }}>Reset</button>
      <p style={{ margin: '10px 0 0 0', fontSize: 11, color: '#aaa' }}>Press spacebar or tap the circle</p>
    </div>
  );
}
render(<BpmCalculator/>);
